observations.input:
[
  {
    "role": "user",
    "parts": [
      {
        "type": "text",
        "content": "What are my month over month performance insights the past quarter, by cost, displays, clicks, CTR, sales, CVR? Please split by campaign taxonomy"
      }
    ]
  },
  {
    "role": "assistant",
    "parts": [
      {
        "type": "tool_call",
        "id": "get_custom_report",
        "name": "get_custom_report",
        "arguments": {
          "dimensions": [
            "Campaign"
          ],
          "filters": {
            "dateRange": {
              "from_date": "2025-10-01",
              "to_date": "2025-12-31"
            }
          },
          "timeDimension": "Month",
          "metrics": [
            "Cost",
            "Displays",
            "Clicks",
            "Ctr",
            "Sales",
            "Cvr"
          ]
        }
      },
      {
        "type": "Microsoft.Extensions.AI.TextReasoningContent",
        "content": {
          "text": "",
          "protectedData": ""
        }
      }
    ]
  },
  {
    "role": "tool",
    "parts": [
      {
        "type": "tool_call_response",
        "id": "get_custom_report",
        "response": {
          "response_status": "Error",
          "message": "ERROR: No data found for dimensions: Campaign and metrics Cost,Displays,Clicks,Ctr,Sales,Cvr."
        }
      }
    ]
  }
]

