{"attributes":{"gen_ai.operation.name":"chat","gen_ai.request.model":"gemini-2.5-flash","gen_ai.provider.name":"gcp.vertex_ai","server.address":"aiplatform.googleapis.com","server.port":"443","gen_ai.request.seed":"42","gen_ai.request.temperature":"0","gen_ai.tool.definitions":"[
  {
    "type": "function",
    "name": "get_adset_infos",
    "description": "Retrieves all ad sets matching conditions set in the filter (also referred to as campaigns)\r\nThis method should be called by the agent whenever\r\nit needs information about one or more ad sets.\r\nIt provides a comprehensive list of ad sets with key metadata and status fields.\r\n\r\nReturns:\r\n-------\r\nResponse\r\n    An object containing data with the following information for each ad set:\r\n    - id: The unique identifier of the ad set (also called Campaign ID).\r\n    - name: The name of the ad set.\r\n    - advertiserId: The ID of the advertiser that owns this ad set.\r\n    - objective (MarketingObjective): The marketing objective associated with the ad set: Acquisition or Retention.\r\n    - startDate: The start date of the ad set, if specified.\r\n    - activationStatus: Indicates whether the ad set is currently active: Activated or NotActivated\r\n    - deliveryStatus: Describes the current delivery state of the ad set: Running, Archived or NotRunning\r\n\r\nNotes:\r\n-----\r\nUse this method as the primary source for retrieving ad set (campaign) information.",
    "parameters": {
      "type": "object",
      "properties": {
        "filter": {
          "description": "The filters applied for selecting the ad_sets",
          "type": "object",
          "properties": {
            "adset_ids": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "type": "integer"
              }
            },
            "names": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "type": "string"
              }
            },
            "activation_statuses": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "type": "string",
                "enum": [
                  "NotActivated",
                  "Activated"
                ]
              }
            },
            "objectives": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "type": "string",
                "enum": [
                  "NotSet",
                  "Acquisition",
                  "Retention"
                ]
              }
            },
            "delivery_statuses": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "type": "string",
                "enum": [
                  "Running",
                  "Archived",
                  "NotRunning"
                ]
              }
            }
          }
        }
      },
      "required": [
        "filter"
      ]
    }
  },
  {
    "type": "function",
    "name": "get_custom_report",
    "description": "Calls the API to retrieve client data.\r\n\r\nArgs:\r\n    filters: An object containing the built-in filters.\r\n        Default values are provided if needed.\r\n    timeDimension: Time-based dimension for data projections; specifies the granularity at which data will be grouped.\r\n        Possible values and examples:\r\n            - None: Indicates that the user has not provided any clear time dimension.\r\n                This should be selected when there is no explicit instruction.\r\n                Do NOT infer or assume a value; use None unless the user specifies otherwise.\r\n            - Year: Represents a calendar year.\r\n                Examples: per year, by year, year-over-year comparisons (YoY), yearly trend analysis.\r\n            - Month: Represents a calendar month.\r\n                Examples: per month, by month, month-over-month comparisons (MoM), monthly performance reports.\r\n            - Week: Represents a calendar week.\r\n                Examples: per week, by week, week-over-week comparisons (WoW), weekly campaign summaries.\r\n            - Day: Represents a calendar day.\r\n                Examples: per day, by day, day-over-day comparisons (DoD), daily performance tracking.\r\n            - Hour: Represents an hour within a day.\r\n                Examples: per hour, by hour, hourly trend analysis, intraday performance monitoring.\r\n    dimensions: A list of dimensions that define the granularity of the report.\r\n        Example: [os, device]\r\n    metrics: A list of performance indicators to retrieve.\r\n        Example: [clicks, ctr]\r\n    attributionModel: Specifies the model used to measure sales.\r\n        Optional.\r\n    additionalFilters: Custom filters applied to the data.\r\n        CRITICAL CONSTRAINT: Every dimension used in \u0060additionalFilters\u0060 MUST be present in the \u0060dimensions\u0060 list.\r\n        If a filter references a dimension not included in \u0060dimensions\u0060, the request will be rejected.\r\n\r\nNotes:\r\n    - Dimensions determine the level of detail in the report.\r\n    - Metrics represent the KPIs to monitor campaign performance.\r\n    - Filters restrict the dataset retrieved from the API.\r\n    - \u0060additionalFilters\u0060 allow for extra filtering, but only on dimensions explicitly listed in \u0060dimensions\u0060.",
    "parameters": {
      "type": "object",
      "properties": {
        "filters": {
          "description": "Filters are a way to narrow the scope of the report by setting certain values.\r\nIf no value can be inferred, a default one will be provided.",
          "type": "object",
          "properties": {
            "clientIds": {
              "type": "array",
              "items": {
                "type": "integer"
              }
            },
            "dateRange": {
              "description": "Date range between two dates.\r\nIMPORTANT: from_date and to_date are inclusive (the start and end dates are included in the period).\r\n\r\nIf dates are not given explicitly, they can be deduced as follows:\r\n\r\n- IMPORTANT: Last n days: from = today - n days, to = yesterday (inclusive, does not include today)\r\n    Example: if today is 2025-08-23 then \u0022last 7 days\u0022: 2025-08-16 to 2025-08-22 (inclusive, 7 days)\r\n    Example: if today is 2025-08-10 then \u0022last 20 days\u0022: 2025-07-21 to 2025-08-09 (inclusive, 20 days)\r\n- Month of May 2025: from = 2025-05-01, to = 2025-05-31\r\n- IMPORTANT: Last week, the last full calendar week (Monday to Sunday) before the current Week:\r\n    from = Monday of previous week\r\n    to = Sunday of previous Week\r\n    Example: if today is Tuesday, 2025-08-12 then \u0022last week\u0022 is Monday 2025-08-04 to Sunday 2025-08-10\r\n    Example: if today is Monday, 2025-09-15 then \u0022last week\u0022 is Monday 2025-08-14 to Sunday 2025-08-14\r\n- IMPORTANT: Last n weeks, the last n full calendar weeks (Monday to Sunday) before the current Week.\r\n    n is the number of weeks.\r\n    from = Monday of n weeks ago\r\n    to = Sunday of previous Week\r\n    Example: if today is Friday, 2025-08-22 then \u0022last 2 weeks\u0022 is\r\n        Monday 2025-08-04 to Sunday 2025-08-17\r\n        n is 2\r\n    Example: if today is Monday, 2025-07-21 then \u0022last 3 weeks\u0022 is\r\n        Monday 2025-06-30 to Sunday 2025-07-20\r\n        n is 3\r\n- IMPORTANT: Last month, the last full calendar month before the current month.\r\n    from = first day of previous month\r\n    to = last day of previous month\r\n    Example: if today is Tuesday, 2025-08-19 then \u0022last month\u0022 is 2025-07-01 to 2025-07-31\r\n- IMPORTANT: Last n months, the last n full calendar months before the current month.\r\n    n is the number of months.\r\n    from = first day of the month n months ago\r\n    to = last day of previous month\r\n    Example: if today is Monday, 2025-08-19 then \u0022last 3 months\u0022 is 2025-05-01 to 2025-07-31\r\n        n is 3\r\n- Last quarter: the last full quarter before the current quarter.\r\n    Q1: January 1 to March 31\r\n    Q2: April 1 to June 30\r\n    Q3: July 1 to September 30\r\n    Q4: October 1 to December 31\r\n\r\n\r\ntime_zone is the IANA time zone name (e.g., \u0022Europe/London\u0022, \u0022America/New_York\u0022).\r\nBy default, assume that we are in the Europe/London time zone.\r\n\r\nThe field previous_period_from_date is used to define the starting date of a previous period\r\nthat mirrors the current data collection range.\r\nThis allows for comparative analysis between the current period and a similar past period.\r\n\r\nUse the following guidelines and examples to determine the correct value:\r\n\r\nGeneral Rule:\r\nprevious_period_from_date should be set to a date that starts the previous comparable period\r\nthe previous period will have the same duration as the current one\r\nthe previous period and the current period MUST NOT overlap\r\n\r\n    Examples:\r\n    Relative Time Comparison\r\n        If comparing to last year, and from_date = 2025-08-01, then:\r\n            previous_period_from_date = 2024-08-01\r\n        If comparing with the previous period, previous_period_start_date is calculated\r\n        by subtracting the duration of the current date range from its starting date (from_date).\r\n        This ensures the previous period has the same length and ends\r\n        right before the current one begins.\r\n        Example:\r\n            Current range: from_date = 2025-08-10, to_date = 2025-08-19 (10 days including bounds),\r\n            then: previous_period_start_date = 2025-07-31 (10 days before 2025-08-10)\r\n    Custom Period Comparison\r\n        If comparing to the period starting 2025-02-25, then:\r\n            previous_period_from_date = 2025-02-25\r\n",
              "type": "object",
              "properties": {
                "from_date": {
                  "type": "string",
                  "format": "date"
                },
                "to_date": {
                  "type": "string",
                  "format": "date"
                },
                "time_zone": {
                  "type": [
                    "string",
                    "null"
                  ]
                },
                "previous_period_from_date": {
                  "type": [
                    "string",
                    "null"
                  ],
                  "format": "date"
                }
              }
            },
            "currency": {
              "type": "string"
            },
            "campaignStatus": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "description": "    Status of a campaign\r\n\r\n    Glossary:\r\n        Active\r\n            Active, Running or Live\r\n        NotRunning\r\n            Not running\r\n        Dead\r\n            Archived",
                "type": "string",
                "enum": [
                  "Active",
                  "NotRunning",
                  "Dead"
                ]
              }
            },
            "mediaType": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "description": "    Type of media used. video or display.\r\n\r\n    Glossary:\r\n        Display\r\n            HTML display\r\n\r\n        Video\r\n            Video display",
                "type": "string",
                "enum": [
                  "Display",
                  "Video"
                ]
              }
            },
            "marketingCampaignGoals": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "type": "string",
                "enum": [
                  "NotSet",
                  "Acquisition",
                  "Retention"
                ]
              }
            },
            "campaigns": {
              "type": [
                "array",
                "null"
              ],
              "items": {
                "type": "integer"
              }
            }
          }
        },
        "timeDimension": {
          "description": "Defines the time-based dimensions available for data projections.\r\n\r\nEach enum member specifies the granularity at which data can be grouped or analyzed.\r\n\r\nMembers:\r\n    None  - Indicates that the user has not provided any clear time dimension.\r\n        This should be selected when there is no explicit instruction.\r\n        Do NOT infer or assume a value; use None unless the user specifies otherwise.\r\n    Year  - Represents a calendar year. For example per year, by year, year-over-year comparisons (YoY), yearly trend analysis.\r\n    Month - Represents a calendar month. For example per month, by month, month-over-month comparisons (MoM), monthly performance reports.\r\n    Week  - Represents a calendar week. For example per week, by week, week-over-week comparisons (WoW), weekly campaign summaries.\r\n    Day   - Represents a calendar day. For example per day, by day, day-over-day comparisons (DoD), daily performance tracking.\r\n    Hour  - Represents an hour within a day. For example per hour, by hour, hourly trend analysis, intraday performance monitoring.",
          "type": "string",
          "enum": [
            "None",
            "Year",
            "Month",
            "Week",
            "Day",
            "Hour"
          ],
          "default": "None"
        },
        "dimensions": {
          "type": "array",
          "items": {
            "description": "    Enumeration of standardized dimensions used in online advertising projections.\r\n\r\n    Each member represents a dimension or attribute commonly used in digital marketing analytics,\r\n    campaign performance tracking, and audience segmentation.\r\n\r\n    Glossary:\r\n        Advertiser\r\n            Name or entity running the ad campaign(s). Also called Client\r\n\r\n        MarketingCampaign\r\n            Full name of the marketing campaign. A group of ad sets.\r\n\r\n        Campaign\r\n            An ad set.\r\n\r\n        MediaType\r\n            Type of media used (e.g., video, display, native).\r\n\r\n        MarketingCampaignGoal\r\n            Marketing campaign objective (Retention, Acquisition)\r\n\r\n        Category\r\n            Product or content category (e.g., electronics, fashion).\r\n\r\n        Device\r\n            Type of device used (e.g., mobile, desktop, tablet).\r\n\r\n        Os\r\n            Operating system of the device (e.g., iOS, Android, Windows).\r\n\r\n        AdChannel\r\n            Specific advertising channel (e.g., programmatic, direct).\r\n\r\n        AdSocialNetwork\r\n            Social media platform used (e.g., Facebook, TikTok).\r\n\r\n        Ad\r\n            A creative\r\n\r\n        Coupon\r\n            A creative coupon\r\n\r\n        AdFormat\r\n            Format of the ad (e.g., banner, interstitial, carousel).\r\n\r\n        DisplaySize\r\n            Size of the display area for the ad.\r\n\r\n        VideoPlacement\r\n            Placement type for video ads (e.g., in-stream, out-stream).\r\n\r\n        VideoPlaybackMethod\r\n            How the video was played (e.g., autoplay, click-to-play).\r\n\r\n        VideoPlayerSize\r\n            Dimensions of the video player.\r\n\r\n        VideoDurationInSeconds\r\n            Length of the video ad.\r\n\r\n        VideoPlayerRatio\r\n            Aspect ratio of the video player (e.g., 16:9).\r\n\r\n        Ssp\r\n            Supply Side Partner. The publishing network where displays were made.\r\n\r\n        Country\r\n            Country where the ad was served.\r\n\r\n        Region\r\n            Region or state within the country.\r\n\r\n        PostalCode\r\n            Postal or ZIP code.\r\n\r\n        UserBehavior\r\n            Behavioral segment of the user (e.g., frequent buyer).\r\n",
            "type": "string",
            "enum": [
              "Advertiser",
              "MarketingCampaign",
              "Campaign",
              "MediaType",
              "MarketingCampaignGoal",
              "Category",
              "Device",
              "Os",
              "AdChannel",
              "AdSocialNetwork",
              "Ad",
              "Coupon",
              "AdFormat",
              "DisplaySize",
              "VideoPlacement",
              "VideoPlaybackMethod",
              "VideoPlayerSize",
              "VideoDurationInSeconds",
              "VideoPlayerRatio",
              "Ssp",
              "Country",
              "Region",
              "PostalCode",
              "UserBehavior"
            ]
          },
          "default": null
        },
        "metrics": {
          "type": "array",
          "items": {
            "description": "    Metrics represents the quantity that we wish to measure\r\n\r\n    Glossary:\r\n        Audience\r\n            Users or devices that were seen online and were eligible to be served an ad. When\r\n            several devices can be related to one user, it counts for 1, otherwise it reflects the\r\n            number of devices\r\n\r\n        Clicks\r\n            The number of clicks driven by the ads\r\n\r\n        Cost\r\n            The overall cost of your ads or video ads\r\n\r\n        CostPerResult\r\n            What your ad set has cost per configured result unit for your selected period.\r\n\r\n        Cpc\r\n            Cost Per Click - the amount of money spent for the ads to receive one click\r\n\r\n        Cpm\r\n            Cost Per Mille - the amount of money spent per thousand displays, available for CPM\r\n            based ad sets only\r\n\r\n        Ctr\r\n            Click-Through Rate - literally, the rate or frequency at which users click through to a\r\n            landing page from an ad\r\n\r\n        Displays\r\n            The number of times your ads have been shown on a screen\r\n\r\n        Ecpm\r\n            Effective Cost Per Mille - the amount of money spent per thousand displays\r\n\r\n        ExposedUsers\r\n            The number of users who have been served an ad\r\n\r\n        Frequency\r\n            The average number of displays each exposed user has seen.\r\n\r\n        InvalidClicks\r\n            Clicks that don\u0027t meet our quality standards and won\u0027t be billed to you.\r\n\r\n        InvalidDisplays\r\n            Displays that don\u0027t meet our quality standards and won\u0027t be billed to you.\r\n\r\n        Reach\r\n            Share of online eligible users or devices who have been served an ad\r\n\r\n        Result\r\n            What your ad set has achieved based on your configuration for your selected period.\r\n\r\n        UntrackableDisplays\r\n\r\n        NonViewableDisplays\r\n\r\n        Viewability\r\n            The percentage of displayed ads or videos ads that were considered viewable\r\n\r\n        ViewableDisplays\r\n            The number of times at least 50% of the ad appeared for at least 1 second for ads and 2\r\n            seconds for videos ads, once started\r\n\r\n        Visits\r\n            The number of users that were active on your site or app in the hour following clicking\r\n            on your ad\r\n\r\n        Winrate\r\n            Number of displays divided by the total number of display opportunities\r\n\r\n        BounceRate\r\n            Proportion of website visitors leaving after seeing only one page\r\n\r\n        Cpv\r\n            Cost Per Visit - the amount of money spent to get one visit on your website\r\n\r\n        AppInstall\r\n            The number of installations of application\r\n\r\n        Cpi\r\n            Cost Per Install - the amount of money that needs to be spent to get one app installed\r\n\r\n        Cpqv\r\n            Cost Per Qualified Visit - the amount of money spent to get one qualified visit on your\r\n            website\r\n\r\n        InstallRate\r\n            Install Rate - the percentage of completed app installs compared to the clicks that\r\n            occurred\r\n\r\n        QualifiedVisits\r\n            The number of users on the target website for which at least two events or one sale\r\n            event occurred within the hour following the click\r\n\r\n        Assists\r\n            The number of sales one of your campaigns or ad sets contributed to (with clicks or\r\n            displays) on your site or app.\r\n\r\n        AvgCart\r\n            Average revenue generated by a sale\r\n\r\n        Cos\r\n            Cost Of Sales - the ratio between the cost generated by the ad set(s) vs. the revenue\r\n            generated by the sales, figured as a percentage\r\n\r\n        Cpov\r\n            Cost Per Store Visit - the amount of money spent to get one visit on your physical store\r\n\r\n        Cov\r\n            Cost Of advertiser Value - the ratio between the advertiser value generated by the sales\r\n            vs. the cost generated by the ad set(s), figured as a percentage\r\n\r\n        Cpo\r\n            Cost Per Order - the amount of money that needs to be spent to get one order or\r\n            transaction\r\n\r\n        Cvr\r\n            ConVersion Rate - the percentage of completed purchases compared to the clicks that\r\n            occurred\r\n\r\n        AssistsSalesRatio\r\n            The ratio between your assisted sales and sales made on your site or app.\r\n\r\n        OmnichannelRevenue\r\n            The revenue generated by online and in-store sales.\r\n\r\n        OmnichannelRoas\r\n            Omnichannel Return on Ad Spend. The ratio between revenue generated online and in-store,\r\n            and the cost.\r\n\r\n        OmnichannelSales\r\n            The number of online and in store transactions or conversions resulting from Criteo ads.\r\n\r\n        Revenue\r\n            The amount of money generated by the online sales\r\n\r\n        Roas\r\n            Return On Ad Spend - the ratio between the revenue generated and the cost\r\n\r\n        Sales\r\n            The number of completed e-commerce transactions or purchases\r\n\r\n        OfflineRevenue\r\n            The amount of revenue generated by in-store sales.\r\n\r\n        OfflineRoas\r\n            Store Return on Ad Spend. The ratio between the revenue generated in-store and the cost.\r\n\r\n        OfflineSales\r\n            The number of completed in-store transactions or purchases.\r\n\r\n        OfflineVisits\r\n            The number of visits to one of the physical stores\r\n\r\n        Currency\r\n\r\n        VideoAvoc\r\n            The number of times one of your videos was viewable and audible when it reached\r\n            completion\r\n\r\n        VideoCompletionRate\r\n            The percentage of started videos that played for their entire duration\r\n\r\n        VideoCpcv\r\n            The average cost of a video played for its entire duration\r\n\r\n        VideoCpv\r\n            The average cost of a video that started playing\r\n\r\n        VideoComplete\r\n            The number of times one of your videos played for its entire duration\r\n\r\n        VideoFirstQuartile\r\n            The number of times one of your videos played to 25% of its duration\r\n\r\n        VideoMidpoint\r\n            The number of times one of your videos played to 50% of its duration\r\n\r\n        VideoThirdQuartile\r\n            The number of times one of your videos played to 75% of its duration\r\n\r\n        VideoAverageViewRate\r\n            The average played percentage of a started video\r\n\r\n        VideoStartRate\r\n            The percentage of displayed videos that started playing\r\n\r\n        VideoStart\r\n            The number of times one of your ads started playing",
            "type": "string",
            "enum": [
              "Audience",
              "Clicks",
              "Cost",
              "CostPerResult",
              "Cpc",
              "Cpm",
              "Ctr",
              "Displays",
              "Ecpm",
              "ExposedUsers",
              "Frequency",
              "InvalidClicks",
              "InvalidDisplays",
              "Reach",
              "Result",
              "UntrackableDisplays",
              "NonViewableDisplays",
              "Viewability",
              "ViewableDisplays",
              "Visits",
              "Winrate",
              "BounceRate",
              "Cpv",
              "AppInstall",
              "Cpi",
              "Cpqv",
              "InstallRate",
              "QualifiedVisits",
              "Assists",
              "AvgCart",
              "Cos",
              "Cpov",
              "Cov",
              "Cpo",
              "Cvr",
              "AssistsSalesRatio",
              "OmnichannelRevenue",
              "OmnichannelRoas",
              "OmnichannelSales",
              "Revenue",
              "Roas",
              "Sales",
              "OfflineRevenue",
              "OfflineRoas",
              "OfflineSales",
              "OfflineVisits",
              "Currency",
              "VideoAvoc",
              "VideoCompletionRate",
              "VideoCpcv",
              "VideoCpv",
              "VideoComplete",
              "VideoFirstQuartile",
              "VideoMidpoint",
              "VideoThirdQuartile",
              "VideoAverageViewRate",
              "VideoStartRate",
              "VideoStart"
            ]
          },
          "default": null
        },
        "attributionModel": {
